import { useEffect, useRef } from 'react';

export function FirstField() {
  const r = useRef<HTMLInputElement>(null);
  useEffect(() => {
    r.current?.focus();
  }, []);
  return <input ref={r} />;
}

const id = useId();
return (
  <>
    <label htmlFor={id}>Email</label>
    <input id={id} type="email" />
  </>
);
